CREATE EXTENSION IF NOT EXISTS pgcrypto;
DO $$ BEGIN CREATE TYPE tenant_status AS ENUM ('active','inactive'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE program_status AS ENUM ('active','inactive'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE day_status AS ENUM ('available','coming_soon'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE enrollment_status AS ENUM ('active','completed','cancelled'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE progress_status AS ENUM ('not_started','in_progress','completed'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

CREATE TABLE IF NOT EXISTS "user" (id text PRIMARY KEY,name text NOT NULL,email text NOT NULL UNIQUE,email_verified boolean NOT NULL DEFAULT false,image text,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS session (id text PRIMARY KEY,expires_at timestamptz NOT NULL,token text NOT NULL UNIQUE,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),ip_address text,user_agent text,user_id text NOT NULL REFERENCES "user"(id) ON DELETE CASCADE);
CREATE INDEX IF NOT EXISTS session_user_id_idx ON session(user_id);
CREATE TABLE IF NOT EXISTS account (id text PRIMARY KEY,account_id text NOT NULL,provider_id text NOT NULL,user_id text NOT NULL REFERENCES "user"(id) ON DELETE CASCADE,access_token text,refresh_token text,id_token text,access_token_expires_at timestamptz,refresh_token_expires_at timestamptz,scope text,password text,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS account_user_id_idx ON account(user_id);
CREATE TABLE IF NOT EXISTS verification (id text PRIMARY KEY,identifier text NOT NULL,value text NOT NULL,expires_at timestamptz NOT NULL,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS verification_identifier_idx ON verification(identifier);
CREATE TABLE IF NOT EXISTS rate_limit (id text PRIMARY KEY,key text NOT NULL UNIQUE,count integer NOT NULL,last_request integer NOT NULL);
CREATE TABLE IF NOT EXISTS tenants (id text PRIMARY KEY,slug text NOT NULL UNIQUE,product_name text NOT NULL,short_name text NOT NULL,status tenant_status NOT NULL DEFAULT 'active',branding jsonb NOT NULL,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS tenant_domains (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,hostname text NOT NULL UNIQUE,is_primary boolean NOT NULL DEFAULT false,created_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS tenant_domains_tenant_idx ON tenant_domains(tenant_id);
CREATE TABLE IF NOT EXISTS tenant_memberships (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,user_id text NOT NULL REFERENCES "user"(id) ON DELETE CASCADE,role text NOT NULL DEFAULT 'member',created_at timestamptz NOT NULL DEFAULT now(),CONSTRAINT tenant_memberships_tenant_user_uq UNIQUE(tenant_id,user_id));
CREATE INDEX IF NOT EXISTS tenant_memberships_user_idx ON tenant_memberships(user_id);
CREATE TABLE IF NOT EXISTS programs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,slug text NOT NULL,title text NOT NULL,description text NOT NULL,total_days integer NOT NULL,status program_status NOT NULL DEFAULT 'active',created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),CONSTRAINT programs_tenant_slug_uq UNIQUE(tenant_id,slug));
CREATE INDEX IF NOT EXISTS programs_tenant_idx ON programs(tenant_id);
CREATE TABLE IF NOT EXISTS program_days (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),program_id uuid NOT NULL REFERENCES programs(id) ON DELETE CASCADE,day_number integer NOT NULL,slug text NOT NULL,title text NOT NULL,objective text NOT NULL,status day_status NOT NULL,content_blocks jsonb NOT NULL DEFAULT '[]'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),CONSTRAINT program_days_program_day_uq UNIQUE(program_id,day_number));
CREATE INDEX IF NOT EXISTS program_days_program_idx ON program_days(program_id);
CREATE TABLE IF NOT EXISTS enrollments (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,program_id uuid NOT NULL REFERENCES programs(id) ON DELETE CASCADE,user_id text NOT NULL REFERENCES "user"(id) ON DELETE CASCADE,status enrollment_status NOT NULL DEFAULT 'active',started_at timestamptz NOT NULL DEFAULT now(),completed_at timestamptz,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),CONSTRAINT enrollments_program_user_uq UNIQUE(program_id,user_id));
CREATE INDEX IF NOT EXISTS enrollments_tenant_user_idx ON enrollments(tenant_id,user_id);
CREATE TABLE IF NOT EXISTS day_progress (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,enrollment_id uuid NOT NULL REFERENCES enrollments(id) ON DELETE CASCADE,program_day_id uuid NOT NULL REFERENCES program_days(id) ON DELETE CASCADE,status progress_status NOT NULL DEFAULT 'not_started',started_at timestamptz,completed_at timestamptz,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),CONSTRAINT day_progress_enrollment_day_uq UNIQUE(enrollment_id,program_day_id));
CREATE INDEX IF NOT EXISTS day_progress_tenant_enrollment_idx ON day_progress(tenant_id,enrollment_id);
CREATE INDEX IF NOT EXISTS day_progress_day_idx ON day_progress(program_day_id);
CREATE TABLE IF NOT EXISTS reflection_responses (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,user_id text NOT NULL REFERENCES "user"(id) ON DELETE CASCADE,enrollment_id uuid NOT NULL REFERENCES enrollments(id) ON DELETE CASCADE,program_day_id uuid NOT NULL REFERENCES program_days(id) ON DELETE CASCADE,prompt_key text NOT NULL,response_text text NOT NULL,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),CONSTRAINT reflection_enrollment_day_prompt_uq UNIQUE(enrollment_id,program_day_id,prompt_key));
CREATE INDEX IF NOT EXISTS reflection_tenant_user_idx ON reflection_responses(tenant_id,user_id);
